2	import { getCollection, render } from 'astro:content';
3	import BlogPost from '../../../layouts/BlogPost.astro';
4	
5	export async function getStaticPaths() {
6	  const posts = await getCollection('posts');
7	  return posts.map((post) => ({
8	    params: { slug: post.id },
9	    props: { post },
10	  }));
11	}
12	
13	const { post } = Astro.props;
14	const { Content } = await render(post);
15	---
16	
17	<BlogPost post={post}>
18	  <Content />
19	</BlogPost>
