@import "tailwindcss";

/* Custom color scheme */
:root {
  --color-primary: #3b82f6;
  --color-primary-dark: #2563eb;
}

/* Dark mode support */
.dark {
  color-scheme: dark;
}

/* Smooth scrolling */
html {
  scroll-behavior: smooth;
}

/* Base styles */
body {
  @apply bg-white dark:bg-gray-900 text-gray-900 dark:text-gray-100 antialiased;
}

/* Typography enhancements */
.prose {
  @apply max-w-none;
}

.prose code {
  @apply bg-gray-100 dark:bg-gray-800 px-1.5 py-0.5 rounded text-sm;
---
